//! Markdown renderers for the auto-generated catalog reference docs.
//! The output of these functions is written to disk by
//! `vox ci generate-plugin-catalog-docs` (see vox-cli).

use crate::{all_bundles, all_plugins, bundle_resolved, schema::PayloadKind};

const MARKER: &str = "<!-- AUTOGENERATED by `vox ci generate-plugin-catalog-docs` from \
     crates/vox-plugin-catalog/catalog.toml. DO NOT EDIT BY HAND. -->\n\n";

const CATALOG_FRONTMATTER: &str = "---\n\
    title: \"Plugin Catalog (Generated)\"\n\
    description: \"Auto-generated authoritative list of all first-party Vox plugins.\"\n\
    category: \"reference\"\n\
    status: \"current\"\n\
    training_eligible: true\n\
    ---\n\n";

const BUNDLES_FRONTMATTER: &str = "---\n\
    title: \"Distribution Bundles (Generated)\"\n\
    description: \"Auto-generated authoritative list of Vox distribution bundles and their plugin composition.\"\n\
    category: \"reference\"\n\
    status: \"current\"\n\
    training_eligible: true\n\
    ---\n\n";

pub fn render_catalog_md() -> String {
    let mut out = String::from(CATALOG_FRONTMATTER);
    out.push_str(MARKER);
    out.push_str("# Plugin Catalog (Generated)\n\n");
    out.push_str(
        "Authoritative list of every first-party Vox plugin. Sourced from \
         `crates/vox-plugin-catalog/catalog.toml`. See \
         [plugin-catalog.md](plugin-catalog.md) for the prose explanation.\n\n",
    );

    out.push_str("_Columns: `id`, `payload-kind`, `extension-points`/`exposes-tools`, `default-source`, `bundled-in`._\n\n");
    out.push_str("## Code-payload plugins\n\n");
    out.push_str("| id | extension points | default-source | bundled-in |\n");
    out.push_str("|----|------------------|----------------|------------|\n");
    for p in all_plugins()
        .iter()
        .filter(|p| matches!(p.payload_kind, PayloadKind::Code))
    {
        out.push_str(&format_plugin_row(p));
    }
    out.push('\n');

    out.push_str("## Skill-payload plugins\n\n");
    out.push_str("| id | exposes tools | default-source | bundled-in |\n");
    out.push_str("|----|---------------|----------------|------------|\n");
    for p in all_plugins()
        .iter()
        .filter(|p| matches!(p.payload_kind, PayloadKind::Skill))
    {
        out.push_str(&format_skill_row(p));
    }
    out.push('\n');

    out.push_str("## Composite plugins\n\n");
    out.push_str("| id | extension points | exposes tools | default-source |\n");
    out.push_str("|----|------------------|---------------|----------------|\n");
    for p in all_plugins()
        .iter()
        .filter(|p| matches!(p.payload_kind, PayloadKind::Composite))
    {
        out.push_str(&format_composite_row(p));
    }
    out.push('\n');

    out
}

pub fn render_bundles_md() -> String {
    let mut out = String::from(BUNDLES_FRONTMATTER);
    out.push_str(MARKER);
    out.push_str("# Distribution Bundles (Generated)\n\n");
    out.push_str(
        "First-party Vox distribution bundles. Each bundle is the same host \
         binary plus a curated `plugins/` directory. See \
         [distribution-bundles.md](distribution-bundles.md) for the decision \
         tree.\n\n",
    );

    out.push_str("| bundle | extends | direct plugins | total resolved plugins |\n");
    out.push_str("|--------|---------|----------------|------------------------|\n");
    for b in all_bundles() {
        let resolved_count = bundle_resolved(&b.id)
            .map(|v| v.len().to_string())
            .unwrap_or_else(|e| format!("ERR: {e}"));
        out.push_str(&format!(
            "| `{}` | {} | {} | {} |\n",
            b.id,
            b.extends
                .as_deref()
                .map(|s| format!("`{s}`"))
                .unwrap_or_else(|| "—".to_string()),
            b.plugins.len(),
            resolved_count,
        ));
    }
    out.push('\n');

    out.push_str("## Per-bundle plugin lists\n\n");
    for b in all_bundles() {
        out.push_str(&format!("### `{}`\n\n", b.id));
        out.push_str(&format!("{}\n\n", b.description));
        if let Some(parent) = &b.extends {
            out.push_str(&format!("Extends: `{parent}`\n\n"));
        }
        match bundle_resolved(&b.id) {
            Ok(plugins) if plugins.is_empty() => {
                out.push_str("_No plugins (bare host binary)._\n\n");
            }
            Ok(plugins) => {
                for p in plugins {
                    out.push_str(&format!("- `{}` — {}\n", p.id, p.description));
                }
                out.push('\n');
            }
            Err(e) => {
                out.push_str(&format!("**ERROR:** {e}\n\n"));
            }
        }
    }

    out
}

fn format_plugin_row(p: &crate::schema::PluginCatalogEntry) -> String {
    format!(
        "| `{}` | {} | `{}` | {} |\n",
        p.id,
        p.extension_points
            .as_ref()
            .map(|v| v
                .iter()
                .map(|s| format!("`{s}`"))
                .collect::<Vec<_>>()
                .join(", "))
            .unwrap_or_default(),
        p.default_source,
        if p.bundled_in.is_empty() {
            "—".to_string()
        } else {
            p.bundled_in
                .iter()
                .map(|s| format!("`{s}`"))
                .collect::<Vec<_>>()
                .join(", ")
        },
    )
}

fn format_skill_row(p: &crate::schema::PluginCatalogEntry) -> String {
    format!(
        "| `{}` | {} | `{}` | {} |\n",
        p.id,
        p.exposes_tools
            .as_ref()
            .map(|v| v
                .iter()
                .map(|s| format!("`{s}`"))
                .collect::<Vec<_>>()
                .join(", "))
            .unwrap_or_default(),
        p.default_source,
        if p.bundled_in.is_empty() {
            "—".to_string()
        } else {
            p.bundled_in
                .iter()
                .map(|s| format!("`{s}`"))
                .collect::<Vec<_>>()
                .join(", ")
        },
    )
}

fn format_composite_row(p: &crate::schema::PluginCatalogEntry) -> String {
    format!(
        "| `{}` | {} | {} | `{}` |\n",
        p.id,
        p.extension_points
            .as_ref()
            .map(|v| v
                .iter()
                .map(|s| format!("`{s}`"))
                .collect::<Vec<_>>()
                .join(", "))
            .unwrap_or_default(),
        p.exposes_tools
            .as_ref()
            .map(|v| v
                .iter()
                .map(|s| format!("`{s}`"))
                .collect::<Vec<_>>()
                .join(", "))
            .unwrap_or_default(),
        p.default_source,
    )
}
